//typescript
// Generated by BugRepro — from screenshots/04-20.png
// Page: Zenn記事ページ（Playwright vs Puppeteer）

import { test, expect, type Page } from "@playwright/test";

const ARTICLE_URL = "https://zenn.dev/ikuyadeu/articles/playwright-vs-puppeteer";

test.describe("Zenn記事ページ", () => {
  let page: Page;

  test.beforeEach(async ({ browser }) => {
    page = await browser.newPage();
    await page.goto(ARTICLE_URL);
  });

  test.afterEach(async () => {
    await page.close();
  });

  // --- ヘッダー ---

  test("Zennロゴが表示される", async () => {
    await expect(page.getByRole("link", { name: /zenn/i }).first()).toBeVisible();
  });

  test("Log inボタンが表示される", async () => {
    await expect(page.getByRole("link", { name: "Log in" })).toBeVisible();
  });

  // --- 記事メタ情報 ---

  test("記事タイトルが正しく表示される", async () => {
    await expect(
      page.getByRole("heading", { name: /Puppeteerを使う理由はなくなった/ })
    ).toBeVisible();
  });

  test("公開日が表示される", async () => {
    await expect(page.getByText("2021/04/19")).toBeVisible();
  });

  test("タグ「Playwright」が表示される", async () => {
    await expect(page.getByRole("link", { name: "Playwright" })).toBeVisible();
  });

  test("タグ「Puppeteer」が表示される", async () => {
    await expect(page.getByRole("link", { name: "Puppeteer" })).toBeVisible();
  });

  test("タグ「Idea」が表示される", async () => {
    await expect(page.getByRole("link", { name: "Idea" })).toBeVisible();
  });

  // --- リアクションバー ---

  test("いいね数が0以上である", async () => {
    const likeButton = page.getByRole("button", { name: /like|いいね/i }).first();
    const text = await likeButton.textContent();
    const count = parseInt(text?.replace(/\D/g, "") ?? "0", 10);
    expect(count).toBeGreaterThanOrEqual(0);
  });

  test("ブックマークボタンが表示される", async () => {
    await expect(page.getByRole("button", { name: /bookmark|ブックマーク/i })).toBeVisible();
  });

  test("シェアボタンが表示される", async () => {
    await expect(page.getByRole("button", { name: /share|シェア/i })).toBeVisible();
  });

  // --- 著者カード ---

  test("著者名「Yusuke Iwaki」が表示される", async () => {
    await expect(page.getByText("Yusuke Iwaki")).toBeVisible();
  });

  test("フォローボタンが表示される", async () => {
    await expect(page.getByRole("button", { name: "フォロー" })).toBeVisible();
  });

  test("バッジを贈るボタンが表示される", async () => {
    await expect(page.getByRole("button", { name: "バッジを贈る" })).toBeVisible();
  });

  // --- 目次 ---

  test("目次セクションが表示される", async () => {
    await expect(page.getByText("目次")).toBeVisible();
  });
});


